import * as z from "zod";
export const GeoJSONGeometryTypeSchema = z.enum([
    "Point",
    "MultiPoint",
    "LineString",
    "MultiLineString",
    "Polygon",
    "MultiPolygon",
    "GeometryCollection",
]);
// The enum of the type values
export const GeoJSONGeometryType = GeoJSONGeometryTypeSchema.enum;
